INSERT INTO ventures (id, slug, name, location, city, type, status, featured, price_label, tagline, summary, extent, plots, size_range, map_query, highlights, amenities, approvals, connectivity, cover_image) VALUES ('serenity-heights', 'serenity-heights', 'SR Serenity Heights', 'Nadergul', 'Hyderabad', 'Villa Plots', 'ONGOING', true, 'Price on request', 'A signature gated layout at Nadergul', 'A meticulously planned, HMDA-approved gated community on the Badangpet–Adibatla main road, offering exclusive villa plots with clear titles, concealed infrastructure and lush landscaping.', NULL, NULL, '152 – 413 Sq. Yds', 'Nadergul, Hyderabad, Telangana', ARRAY['HMDA-approved premium layout with clear titles','Elegant 30 ft concrete roads','Exclusive villa plots from 152 to 413 sq. yds','Concealed underground infrastructure','Two years of professional maintenance support','Loan assistance from leading banks']::text[], ARRAY['Landscaped avenues & curated open spaces','Children''s play zone & lifestyle parks','Underground electricity & drainage','Manicured gardens','Gated entry']::text[], ARRAY['HMDA Approved']::text[], '[{"label":"ORR Raviryal Exit","time":"Minutes away"},{"label":"Rajiv Gandhi Intl. Airport","time":"~30 mins"},{"label":"Adibatla IT / TCS corridor","time":"Nearby"}]'::jsonb, '/ventures/serenity-heights.jpg') ON CONFLICT (id) DO NOTHING;
INSERT INTO ventures (id, slug, name, location, city, type, status, featured, price_label, tagline, summary, extent, plots, size_range, map_query, highlights, amenities, approvals, connectivity, cover_image) VALUES ('sr-eco-park', 'sr-eco-park', 'SR Eco Park', 'Nadergul', 'Hyderabad', 'Open Plots', 'ONGOING', true, 'Price on request', 'An oasis of peace at Nadergul', 'Premium residential plots set across 17.57 acres — a green, family-friendly community with groves, wellness zones and complete underground infrastructure to build homes, lives and legacies.', '17.57 Acres', '225 Plots', '150 – 594 Sq. Yds', 'Nadergul, Hyderabad, Telangana', ARRAY['17.57 acres · 225 plots','Plot sizes from 150 to 594 sq. yds','40 ft and 30 ft CC roads','Compound wall on all sides','24×7 security & provision for Krishna water','Underground sump, electricity & drainage']::text[], ARRAY['Grand entrance plaza','Jogging track & EPDM kids'' play court','Cricket net & badminton court','Meditation & yoga zones','Mango grove & coconut grove','Summer park, party lawn & seating alcoves']::text[], ARRAY['Approved layout']::text[], '[{"label":"Outer Ring Road","time":"Close by"},{"label":"Rajiv Gandhi Intl. Airport","time":"Short drive"},{"label":"Adibatla / Hardware Park","time":"Nearby"}]'::jsonb, '/ventures/sr-eco-park.jpg') ON CONFLICT (id) DO NOTHING;
INSERT INTO ventures (id, slug, name, location, city, type, status, featured, price_label, tagline, summary, extent, plots, size_range, map_query, highlights, amenities, approvals, connectivity, cover_image) VALUES ('sr-infinity-villas', 'sr-infinity-villas', 'SR Infinity Villas', 'Nadergul', 'Hyderabad', 'Villas', 'ONGOING', true, 'Price on request', 'Private villas, club lifestyle', 'A gated enclave of 110 luxury 3 BHK villas across 7.57 acres, where private living and resort-style clubhouse amenities coexist — five minutes from ORR Exit 14.', '7.57 Acres', '110 Villas', '167 – 211 Sq. Yds', 'Nadergul, Hyderabad, Telangana', ARRAY['7.57 acres · 110 luxury villas','3 BHK, G+2 floors','Villa sizes 167 / 183 / 211 sq. yds','Clubhouse with lifestyle amenities','Smooth internal roads & grand entrance']::text[], ARRAY['Clubhouse','Pickleball & multi-purpose court','Outdoor gym','Home theatre','Landscaped surroundings']::text[], ARRAY['Gated villa community']::text[], '[{"label":"ORR Exit 14","time":"5 mins"},{"label":"Rajiv Gandhi Intl. Airport","time":"15 mins"},{"label":"Adibatla (TCS) IT Park","time":"Nearby"},{"label":"Aga Khan Academy","time":"Nearby"}]'::jsonb, '/ventures/sr-infinity-villas.jpg') ON CONFLICT (id) DO NOTHING;
