INSERT INTO testimonials (id, name, location, project, rating, quote, sort_order) VALUES ('tm-1', 'Rajesh K.', 'Hyderabad', 'SR Eco Park', 5, 'The clarity on titles and approvals made the decision easy. Registration was smooth and the layout is exactly as shown.', 0) ON CONFLICT (id) DO NOTHING;
INSERT INTO testimonials (id, name, location, project, rating, quote, sort_order) VALUES ('tm-2', 'Sowmya R.', 'Bengaluru', 'SR Serenity Heights', 5, 'I was investing from another city, so transparency mattered most. Every question was answered clearly over WhatsApp before I visited.', 1) ON CONFLICT (id) DO NOTHING;
INSERT INTO testimonials (id, name, location, project, rating, quote, sort_order) VALUES ('tm-3', 'Imran S.', 'Hyderabad', 'SR Infinity Villas', 4, 'The location near ORR Exit 14 sold me. Good connectivity and the clubhouse plans look genuinely well thought out.', 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO faqs (id, question, answer, sort_order) VALUES ('faq-1', 'Are Sharanya Properties Hub layouts approved?', 'Our flagship layouts such as SR Serenity Heights are HMDA-approved with clear titles. Approval status for each venture is listed on its project page — ask us on WhatsApp for the specific approval documents of any project.', 0) ON CONFLICT (id) DO NOTHING;
INSERT INTO faqs (id, question, answer, sort_order) VALUES ('faq-2', 'Which areas do you develop in?', 'We focus on Hyderabad''s high-growth ORR corridor — currently Nadergul, Majeedpur, Hasthinapuram and surrounding areas with strong connectivity to the Outer Ring Road, Rajiv Gandhi International Airport and the Adibatla IT/aerospace hub.', 1) ON CONFLICT (id) DO NOTHING;
INSERT INTO faqs (id, question, answer, sort_order) VALUES ('faq-3', 'What plot sizes are available?', 'Plot and villa sizes vary by project — for example, SR Eco Park offers 150–594 sq. yds and SR Infinity Villas offers 167–211 sq. yd villas. See each project page for its size range.', 2) ON CONFLICT (id) DO NOTHING;
INSERT INTO faqs (id, question, answer, sort_order) VALUES ('faq-4', 'Do you offer home-loan assistance?', 'Yes. Several of our layouts have tie-ups with leading banks for loan assistance. Share your requirement and we''ll guide you on eligible options.', 3) ON CONFLICT (id) DO NOTHING;
INSERT INTO faqs (id, question, answer, sort_order) VALUES ('faq-5', 'How do I book a site visit?', 'Call or WhatsApp us on +91 94937 02929, or submit an enquiry on any project page. We''ll arrange a convenient site visit and walk you through the layout, pricing and documentation.', 4) ON CONFLICT (id) DO NOTHING;
INSERT INTO faqs (id, question, answer, sort_order) VALUES ('faq-6', 'Is the price fixed or negotiable?', 'Pricing depends on plot size, location within the layout and current availability. Contact us for the latest per-sq-yd pricing and any ongoing offers for a specific venture.', 5) ON CONFLICT (id) DO NOTHING;
INSERT INTO site_settings (id, data) VALUES ('site', '{"name":"Sharanya Properties Hub","legalName":"Sharanya Properties Hub Hyderabad","tagline":"HMDA & DTCP approved plotted developments across Hyderabad","description":"Sharanya Properties Hub develops premium, approved open plots and villa layouts across Hyderabad''s ORR growth corridor — clear titles, gated infrastructure, and locations built for long-term value.","url":"https://sharanyaproperties.in","city":"Hyderabad","region":"Telangana","country":"IN","phone":"+919493702929","phoneDisplay":"+91 94937 02929","whatsapp":"919493702929","email":"info@sharanyaproperties.in","address":"Nadergul, Hyderabad, Telangana","whatsappMessage":"Hi Sharanya Properties Hub, I''d like details about your plotted projects.","social":{"instagram":"","facebook":"","youtube":""}}'::jsonb) ON CONFLICT (id) DO NOTHING;
